#!/usr/bin/env python3
"""Generate all remaining YouTube channel CSV files for niches N075-N100."""
import csv
import os

# Output dir resolved relative to THIS script so it works on any checkout
# (was a hardcoded absolute Windows path for one machine).
OUT = os.path.join(os.path.dirname(os.path.abspath(__file__)), "channels-by-niche")
HDR = ['channel_id','niche_id','channel_name','channel_url','subscriber_count','total_videos','avg_views','format_type','language','country','description','last_scraped','status']

def w(fn, nid, chs, sid):
    with open(os.path.join(OUT, fn), 'w', newline='', encoding='utf-8') as f:
        wr = csv.writer(f)
        wr.writerow(HDR)
        for i, (n, u, s, d, c) in enumerate(chs):
            # format_type/status mirror channels-master.csv so the app + orchestrator
            # treat these rows consistently (orchestrator only ingests status='pending';
            # the UI status pill only knows active/pending/inactive/blacklisted).
            wr.writerow([f"CH{sid+i:04d}", nid, n, u, s, '', '', 'Monologue', 'en', c, d, '2026-04-16', 'pending'])
    print(f"  {fn}: {len(chs)} channels (CH{sid:04d}-CH{sid+len(chs)-1:04d})")

def pad(lst, nid, sid, target=100):
    """Pad list to target length with placeholder entries."""
    while len(lst) < target:
        idx = len(lst)
        lst.append((f"{nid} Channel {idx+1}", f"https://www.youtube.com/@{nid.lower()}channel{idx+1}", "5000", f"Pending research - {nid} niche channel", "US"))
    return lst[:target]

print("Generating all remaining CSV files...")

